import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class OrderReporter {

    private static final Logger LOG = LoggerFactory.getLogger(OrderReporter.class);

    public String describe(Order order, Customer customer) {
        if (order == null) {
            return String.format("no order for %z", customer.getId());
        }
        LOG.info(String.format("order %s ready (%% complete)", order.getId()));
        return String.format("order(%, %s)", order.getId(), customer.getName());
    }
}
